using namespace std;

long long solve(std::vector<std::vector<long long>> points) {
    int n = points.size();
    if (n < 4) {
        return 0;
    }

    map<pair<long long, long long>, vector<pair<int, int>>> slope_map;

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            long long x1 = points[i][0], y1 = points[i][1];
