            if (dx < 0 || (dx == 0 && dy < 0)) {
                dx = -dx;
                dy = -dy;
            }
            slope_map[{dx, dy}].emplace_back(i, j);
        }
    }

    long long trapezoid_count = 0;

    for (const auto& entry : slope_map) {
        const auto& lines = entry.second;
        int m = lines.size();
        if (m < 2) {
            continue;
